import{_ as r,o as n,c as o,ag as d}from"./chunks/framework.BZohXCq9.js";const l=JSON.parse('{"title":"03 — Thuật ngữ (Glossary)","description":"","frontmatter":{},"headers":[],"relativePath":"01-nghiep-vu/03-thuat-ngu.md","filePath":"01-nghiep-vu/03-thuat-ngu.md"}'),e={name:"01-nghiep-vu/03-thuat-ngu.md"};function h(a,t,i,g,s,c){return n(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="_03-—-thuat-ngu-glossary" tabindex="-1">03 — Thuật ngữ (Glossary) <a class="header-anchor" href="#_03-—-thuat-ngu-glossary" aria-label="Permalink to &quot;03 — Thuật ngữ (Glossary)&quot;">​</a></h1><blockquote><p><strong>Vai trò đọc</strong>: ai mới vào dự án — đọc 1 lần để hiểu thuật ngữ trong doc + chat team. Sắp xếp theo nhóm thay vì alphabet để học theo ngữ cảnh.</p></blockquote><hr><h2 id="a-kinh-doanh-—-du-lich" tabindex="-1">A. Kinh doanh — du lịch <a class="header-anchor" href="#a-kinh-doanh-—-du-lich" aria-label="Permalink to &quot;A. Kinh doanh — du lịch&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa đời thường</th></tr></thead><tbody><tr><td><strong>B2C</strong></td><td>Bán trực tiếp cho khách lẻ (Business-to-Consumer) — Vivu Phase 1</td></tr><tr><td><strong>B2B</strong></td><td>Bán cho doanh nghiệp/công ty (Business-to-Business) — Vivu Phase 1 chỉ qua <code>InquiryRequest</code></td></tr><tr><td><strong>MICE</strong></td><td>Meetings, Incentives, Conferences, Exhibitions — du lịch sự kiện công ty. Vivu không làm Phase 1</td></tr><tr><td><strong>Tour operator</strong></td><td>Công ty tự đóng gói tour + bán cho khách cuối (Vivu, Vietravel) — khác với OTA (Online Travel Agent — sàn như Klook, Booking)</td></tr><tr><td><strong>Tour package</strong></td><td>Tour trọn gói gồm xe + hotel + ăn + guide + vé tham quan. Khách trả 1 cục</td></tr><tr><td><strong>Series Tour</strong></td><td>Tour ghép — Vivu set sẵn ngày khởi hành + giá per-pax, khách lẻ book chung đoàn 15-20 người</td></tr><tr><td><strong>Private Tour</strong></td><td>Tour riêng cho 1 nhóm (gia đình, công ty) — không ghép, ngày tự do, quote riêng</td></tr><tr><td><strong>Departure</strong></td><td>1 lịch khởi hành cụ thể của 1 tour (vd Tour Đà Lạt 4N3Đ ngày 15/06/2026)</td></tr><tr><td><strong>Itinerary</strong></td><td>Lịch trình chi tiết từng ngày của tour</td></tr><tr><td><strong>Allotment</strong></td><td>Phòng-đêm Vivu đã ký giữ trước với hotel (vd 100 phòng-đêm tháng 6)</td></tr><tr><td><strong>Cut-off date</strong></td><td>Hạn cuối Vivu phải release phòng không bán được (3-7 ngày trước check-in)</td></tr><tr><td><strong>Free-sale</strong></td><td>Mô hình ký allotment, Vivu được giữ phòng + bán tự do đến cut-off</td></tr><tr><td><strong>No-show</strong></td><td>Khách không xuất hiện → Vivu vẫn phải trả hotel theo HĐ</td></tr><tr><td><strong>Wash</strong></td><td>Tour không đủ số tối thiểu phải cancel → khách bực, brand giảm</td></tr></tbody></table><hr><h2 id="b-kinh-te-đon-hang" tabindex="-1">B. Kinh tế đơn hàng <a class="header-anchor" href="#b-kinh-te-đon-hang" aria-label="Permalink to &quot;B. Kinh tế đơn hàng&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa đời thường</th></tr></thead><tbody><tr><td><strong>Markup</strong></td><td>Tiền chênh lệch giá vốn vs giá bán (lãi gộp)</td></tr><tr><td><strong>Revenue</strong></td><td>Doanh thu — tổng tiền khách trả</td></tr><tr><td><strong>COGS</strong> (Cost of Goods Sold)</td><td>Giá vốn — tiền Vivu chi cho hotel/xe/guide/ăn</td></tr><tr><td><strong>Gross profit</strong></td><td>Lợi nhuận gộp = Revenue − COGS</td></tr><tr><td><strong>Net profit</strong></td><td>Lợi nhuận thực = Gross profit − lương − marketing − thuế − tất cả overhead</td></tr><tr><td><strong>Variable cost</strong></td><td>Chi phí biến đổi — phát sinh theo từng đơn (hotel/xe/guide)</td></tr><tr><td><strong>Fixed cost</strong></td><td>Chi phí cố định — trả đều mỗi tháng (lương, hosting, văn phòng)</td></tr><tr><td><strong>Break-even</strong></td><td>Điểm hoà vốn — gross profit = fixed cost (tháng đó không lỗ không lãi)</td></tr><tr><td><strong>Runway</strong></td><td>Số tháng tiền còn lại trước khi cạn vốn</td></tr><tr><td><strong>AOV</strong> (Average Order Value)</td><td>Trung bình mỗi đơn bao nhiêu tiền</td></tr><tr><td><strong>CAC</strong> (Customer Acquisition Cost)</td><td>Tốn bao nhiêu marketing để có 1 khách mới</td></tr><tr><td><strong>LTV</strong> (Lifetime Value)</td><td>Tổng tiền 1 khách chi cho Vivu suốt vòng đời</td></tr><tr><td><strong>Conversion rate</strong></td><td>Tỉ lệ khách vào web → khách book</td></tr><tr><td><strong>Repeat rate</strong></td><td>Tỉ lệ khách book lần 2+</td></tr><tr><td><strong>KPI</strong></td><td>Key Performance Indicator — chỉ số đo hiệu quả</td></tr><tr><td><strong>MVP</strong></td><td>Minimum Viable Product — phiên bản tối thiểu khả thi để launch</td></tr><tr><td><strong>YAGNI</strong></td><td>You Aren&#39;t Gonna Need It — đừng làm cái chưa cần (anti-scope-creep)</td></tr></tbody></table><hr><h2 id="c-tech-architecture" tabindex="-1">C. Tech &amp; Architecture <a class="header-anchor" href="#c-tech-architecture" aria-label="Permalink to &quot;C. Tech &amp; Architecture&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa đời thường</th></tr></thead><tbody><tr><td><strong>Monorepo</strong></td><td>Nhiều project (web, app, doc) trong cùng 1 git repo</td></tr><tr><td><strong>App Router</strong></td><td>Cách routing mới của Next.js 13+ (folder-based, Server Components mặc định)</td></tr><tr><td><strong>RSC</strong> (React Server Component)</td><td>Component chỉ chạy ở server, không gửi JS xuống browser</td></tr><tr><td><strong>Server Action</strong></td><td>Function chạy server gọi từ form/button client — thay cho REST API cho mutation đơn giản</td></tr><tr><td><strong>ORM</strong></td><td>Object-Relational Mapping — viết code thay cho SQL (Vivu dùng Prisma)</td></tr><tr><td><strong>Migration</strong></td><td>Script đổi schema DB (thêm bảng, đổi cột) version control</td></tr><tr><td><strong>Seed</strong></td><td>Data mẫu insert lúc setup (vd 3 miền <code>mb</code>/<code>mt</code>/<code>mn</code>)</td></tr><tr><td><strong>DDL</strong></td><td>Data Definition Language — SQL đổi schema (CREATE, ALTER, DROP)</td></tr><tr><td><strong>DML</strong></td><td>Data Manipulation Language — SQL đổi data (INSERT, UPDATE, DELETE)</td></tr><tr><td><strong>FK</strong></td><td>Foreign Key — liên kết giữa 2 bảng</td></tr><tr><td><strong>PK</strong></td><td>Primary Key — khoá chính (UUID)</td></tr><tr><td><strong>Cascade</strong></td><td>Khi parent xoá → child xoá theo</td></tr><tr><td><strong>Restrict</strong></td><td>Khi parent xoá nhưng còn child → reject xoá</td></tr><tr><td><strong>SetNull</strong></td><td>Khi parent xoá → child set FK = null</td></tr><tr><td><strong>CHECK constraint</strong></td><td>Quy tắc DB tự enforce (vd <code>rating BETWEEN 1 AND 5</code>)</td></tr><tr><td><strong>Index</strong></td><td>Cấu trúc data tăng tốc query (như mục lục sách)</td></tr><tr><td><strong>Partial index</strong></td><td>Index chỉ chứa subset row (vd <code>WHERE is_active = true</code>)</td></tr><tr><td><strong>B-tree</strong></td><td>Cấu trúc index mặc định Postgres</td></tr><tr><td><strong>Pessimistic lock</strong></td><td>Lock row trước khi đọc (<code>SELECT FOR UPDATE</code>) — chống race</td></tr><tr><td><strong>Optimistic lock</strong></td><td>Check version trước khi update — nhẹ hơn nhưng cần retry</td></tr><tr><td><strong>Transaction Serializable</strong></td><td>Mức cô lập cao nhất — chống mọi anomaly</td></tr><tr><td><strong>Polymorphic</strong></td><td>1 entity tham chiếu nhiều loại target (vd Review → Hotel hoặc Tour)</td></tr><tr><td><strong>Exclusive Arc</strong></td><td>Pattern polymorphic chuẩn DB-level: nhiều FK nullable + CHECK ép đúng 1 non-NULL</td></tr></tbody></table><hr><h2 id="d-seo-marketing-tech" tabindex="-1">D. SEO &amp; Marketing tech <a class="header-anchor" href="#d-seo-marketing-tech" aria-label="Permalink to &quot;D. SEO &amp; Marketing tech&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa đời thường</th></tr></thead><tbody><tr><td><strong>SEO</strong></td><td>Search Engine Optimization — tối ưu để hiện top Google miễn phí</td></tr><tr><td><strong>SERP</strong></td><td>Search Engine Results Page — trang kết quả Google</td></tr><tr><td><strong>Organic traffic</strong></td><td>Khách vào web từ search Google không qua Ads</td></tr><tr><td><strong>Paid traffic</strong></td><td>Khách vào từ quảng cáo (Google Ads, FB Ads)</td></tr><tr><td><strong>Metadata</strong></td><td>Thông tin về trang gửi cho Google (title, description, og:image)</td></tr><tr><td><strong>Structured data</strong></td><td>JSON-LD schema.org — đánh dấu loại nội dung (Tour, Hotel) cho Google hiểu</td></tr><tr><td><strong>Sitemap</strong></td><td>File XML liệt kê tất cả URL → Google biết crawl gì</td></tr><tr><td><strong>Canonical URL</strong></td><td>URL &quot;chuẩn&quot; của 1 trang → tránh duplicate content</td></tr><tr><td><strong>Slug</strong></td><td>Phần URL friendly (vd <code>/tours/tour-da-lat-4-ngay</code>)</td></tr><tr><td><strong>OG image</strong></td><td>Open Graph image — preview khi share FB/Zalo</td></tr><tr><td><strong>CTR</strong> (Click-Through Rate)</td><td>Tỉ lệ người thấy link → click</td></tr><tr><td><strong>Bounce rate</strong></td><td>Tỉ lệ khách vào → out ngay không tương tác</td></tr><tr><td><strong>Lighthouse</strong></td><td>Tool Google đo performance/accessibility/SEO của 1 page (score 0-100)</td></tr><tr><td><strong>Core Web Vitals</strong></td><td>3 metric chính Google đánh giá UX page: LCP, FID, CLS</td></tr></tbody></table><hr><h2 id="e-auth-security" tabindex="-1">E. Auth &amp; Security <a class="header-anchor" href="#e-auth-security" aria-label="Permalink to &quot;E. Auth &amp; Security&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa đời thường</th></tr></thead><tbody><tr><td><strong>Supabase Auth</strong></td><td>Service Supabase quản user — Vivu dùng để xử login</td></tr><tr><td><strong>OAuth</strong></td><td>Login qua bên 3 (Google) — không lưu password</td></tr><tr><td><strong>JWT</strong></td><td>Token xác thực — chứa info user, hết hạn sau 1 thời gian</td></tr><tr><td><strong>Session</strong></td><td>Phiên đăng nhập — Vivu lưu trong cookie HTTPS-only</td></tr><tr><td><strong>CSRF</strong></td><td>Cross-Site Request Forgery — attack giả request từ site khác</td></tr><tr><td><strong>XSS</strong></td><td>Cross-Site Scripting — attack inject JS vào page</td></tr><tr><td><strong>PII</strong></td><td>Personally Identifiable Information — info cá nhân (tên, SDT, email)</td></tr><tr><td><strong>GDPR</strong></td><td>Luật bảo vệ data EU — yêu cầu right-to-erasure (xoá data theo yêu cầu)</td></tr><tr><td><strong>Rate limiting</strong></td><td>Giới hạn số request/phút từ 1 IP — chống bot</td></tr></tbody></table><hr><h2 id="f-operational" tabindex="-1">F. Operational <a class="header-anchor" href="#f-operational" aria-label="Permalink to &quot;F. Operational&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa đời thường</th></tr></thead><tbody><tr><td><strong>Cron job</strong></td><td>Task chạy định kỳ (vd auto-cancel 1 phút/lần)</td></tr><tr><td><strong>Webhook</strong></td><td>URL bên ngoài gọi vào server mình khi có sự kiện (VNPay → mình khi khách trả tiền)</td></tr><tr><td><strong>Idempotency</strong></td><td>Property: gọi lại 1 request 2 lần → kết quả như 1 lần (chống duplicate khi retry)</td></tr><tr><td><strong>Snapshot</strong></td><td>Lưu bản sao state tại thời điểm — vd <code>priceBreakdown</code> snapshot giá khi book</td></tr><tr><td><strong>Audit log</strong></td><td>Bản ghi mọi thay đổi data (<code>ActivityLog</code>) — cho compliance + debug</td></tr><tr><td><strong>Service layer</strong></td><td>Tầng business logic giữa page và DB — page chỉ gọi service, service mới gọi Prisma</td></tr><tr><td><strong>DTO</strong> (Data Transfer Object)</td><td>Object đóng gói data truyền giữa các layer</td></tr></tbody></table><hr><h2 id="g-vivu-specific" tabindex="-1">G. Vivu-specific <a class="header-anchor" href="#g-vivu-specific" aria-label="Permalink to &quot;G. Vivu-specific&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Thuật ngữ</th><th>Định nghĩa</th></tr></thead><tbody><tr><td><strong>Vivu</strong></td><td>Tên brand — tour operator B2C trực tuyến cho thị trường VN</td></tr><tr><td><strong>Phase 1 / 1.5 / 2 / 3+</strong></td><td>Mốc thời gian roadmap (xem <code>../00-san-pham/04-lo-trinh-phat-hanh.md</code>)</td></tr><tr><td><strong>ADR</strong></td><td>Architectural Decision Record — file ghi 1 quyết định technical lớn</td></tr><tr><td><strong><code>travel-web</code></strong></td><td>Repo code Next.js của Vivu</td></tr><tr><td><strong><code>travel-doc</code></strong></td><td>Repo doc (file này nằm trong đây)</td></tr><tr><td><strong>Dashboard L0/L1/L2</strong></td><td>3 tier admin reporting (ADR-007). L0 operational (Phase 1). L1 business metric (Phase 1.5). L2 P&amp;L (Phase 2)</td></tr><tr><td><strong>N-01 → N-04</strong></td><td>4 nguyên tắc DB của Vivu (xem <code>../03-co-so-du-lieu/03-toan-ven-concurrency.md</code>)</td></tr><tr><td><strong>BR-XX</strong></td><td>Business Rule ID (xem <code>02-quy-tac-nghiep-vu.md</code>)</td></tr><tr><td><strong>Anh Khoa / Chị Linh / Admin Vivu</strong></td><td>3 personas chính (xem <code>../00-san-pham/03-personas-user-journey.md</code>)</td></tr></tbody></table><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Luồng nghiệp vụ: <code>01-luong-nghiep-vu-cot-loi.md</code></li><li>Quy tắc nghiệp vụ: <code>02-quy-tac-nghiep-vu.md</code></li><li>Ma trận tính năng: <code>04-ma-tran-tinh-nang.md</code></li><li>Mô hình kinh doanh: <code>../00-san-pham/02-mo-hinh-kinh-doanh.md</code></li></ul>',26)])])}const p=r(e,[["render",h]]);export{l as __pageData,p as default};
